# Route53 Geolocation Record for EU Central (Europe)
resource "aws_route53_record" "eu_central_geo" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = 60

  geolocation_routing_policy {
