resource "aws_codebuild_project" "example" {
  name          = "example-project-${random_id.suffix.hex}"
  description   = "Example CodeBuild project with secondary sources and artifacts"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild.arn

  artifacts {
    type = "S3"
    location = "primary-artifacts-bucket"
    name     = "primary-build-output.zip"
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true

    environment_variable {
      name  = "ENV"
      value = "production"
    }

    environment_variable {
      name  = "AWS_DEFAULT_REGION"
      value = "us-east-1"
    }

    environment_variable {
      name  = "BUILD_VERSION"
      value = "1.0.0"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/primary-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"
  }

  secondary_sources {
    type            = "GITHUB"
    location        = "https://github.com/example/secondary-repo.git"
    source_identifier = "secondary_source_1"
    git_clone_depth = 1
  }

  secondary_sources {
    type            = "S3"
    location        = "secondary-source-bucket/secondary-source.zip"
    source_identifier = "secondary_source_2"
  }

  secondary_artifacts {
    type           = "S3"
    location       = "secondary-artifacts-bucket-1"
    name           = "secondary-output-1.zip"
    packaging      = "ZIP"
    artifact_identifier = "secondary_artifact_1"
  }

  secondary_artifacts {
    type           = "S3"
    location       = "secondary-artifacts-bucket-2"
    name           = "secondary-output-2"
    packaging      = "NONE"
    artifact_identifier = "secondary_artifact_2"
  }

  cache {
    type     = "S3"
    location = "codebuild-cache-bucket/cache"
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "log-group"
      stream_name = "log-stream"
    }

    s3_logs {
      status   = "ENABLED"
      location = "codebuild-logs-bucket/build-log"
    }
  }

  tags = {
    Environment = "production"
    Project     = "example"
  }
}

