  rejection_statement {
    message {
      content      = "Okay, I have cancelled your reservation in progress."
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name           = "TripType"
    description    = "The type of trip to book"
    slot_constraint = "Required"
    slot_type      = "TripTypeValues"
    slot_type_version = "$LATEST"
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What type of trip would you like to book? (Hotel, Flight, Car, or All)"
        content_type = "PlainText"
      }
    }
  }

