```hcl
resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_lex_intent" "book_trip" {
  name = "BookTrip-${random_id.suffix.hex}"

  sample_utterances = [
    "I want to book a trip",
    "Book a trip",
    "I would like to book a trip",
    "Plan a trip",
    "I need to book travel",
  ]

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Okay, I have you down for a {TripType} trip to {Destination} for {Nights} nights. Is this correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your reservation in progress."
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name           = "TripType"
    description    = "The type of trip to book"
    slot_constraint = "Required"
    slot_type      = "TripTypeValues"
    slot_type_version = "$LATEST"
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What type of trip would you like to book? (Hotel, Flight, Car, or All)"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name           = "Destination"
    description    = "The destination city for the trip"
    slot_constraint = "Required"
    slot_type      = "AMAZON.US_CITY"
    priority       = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What city would you like to visit?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name           = "CheckInDate"
    description    = "The check-in date for the trip"
    slot_constraint = "Required"
    slot_type      = "AMAZON.DATE"
    priority       = 3

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "When do you want to check in?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name           = "Nights"
    description    = "The number of nights for the trip"
    slot_constraint = "Required"
    slot_type      = "AMAZON.NUMBER"
    priority       = 4

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "How many nights will you be staying?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name           = "RoomType"
    description    = "The type of room to book"
    slot_constraint = "Required"
    slot_type      = "RoomTypeValues"
    slot_type_version = "$LATEST"
    priority       = 5

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What type of room would you like: queen, king, or deluxe?"
        content_type = "PlainText"
      }
    }
  }
}

