resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  sample_utterances = [
    "I want to order a pizza",
    "I'd like to order pizza",
    "Can I get a pizza",
    "Order a pizza",
    "I want pizza"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name           = "PizzaSize"
    slot_constraint = "Required"
    slot_type      = "PizzaSizeType"
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What size pizza would you like? Small, medium, or large?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name           = "PizzaTopping"
    slot_constraint = "Required"
    slot_type      = "PizzaToppingType"
    priority       = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What toppings would you like on your pizza?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name           = "DeliveryAddress"
    slot_constraint = "Required"
    slot_type      = "AMAZON.PostalAddress"
    priority       = 3

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What address should we deliver the pizza to?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "You ordered a {PizzaSize} pizza with {PizzaTopping} to be delivered to {DeliveryAddress}. Is this correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, your order has been cancelled. Let me know if you'd like to start over."
      content_type = "PlainText"
    }
  }
}

