resource "aws_lex_intent" "modify_order" {
  name        = "ModifyOrder"
  description = "Intent to modify an existing order"

  sample_utterances = [
    "Modify my order",
    "I want to change my order",
    "Update my pizza order",
    "Change my toppings",
    "I need to modify my order"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name           = "OrderNumber"
    slot_constraint = "Required"
    slot_type      = "AMAZON.NUMBER"
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What is your order number?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name           = "ModificationType"
    slot_constraint = "Required"
    slot_type      = "ModificationType"
    priority       = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What would you like to modify? Size, toppings, or delivery address?"
        content_type = "PlainText"
      }
    }
  }
}

