resource "aws_lex_intent" "welcome" {
  name        = "WelcomeIntent"
  description = "Greet kids and welcome them to PizzaPal"

  sample_utterances = [
    "Hi",
    "Hello",
    "Hey PizzaPal",
    "I want pizza",
    "I'm hungry",
    "Let's order pizza"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  conclusion_statement {
    message {
      content      = "Hey there, pizza friend! I'm PizzaPal! What kind of yummy pizza would you like today? You can say things like 'cheese pizza' or 'pepperoni pizza'!"
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizzaIntent"
  description = "Allow kids to order their favorite pizza"

  sample_utterances = [
    "I want a {PizzaType} pizza",
    "Can I get a {PizzaType}",
    "{PizzaType} please",
    "I like {PizzaType}",
    "My favorite is {PizzaType}",
    "Give me {PizzaType}",
    "I want pizza"
  ]

  slot {
    name           = "PizzaType"
    slot_type      = aws_lex_slot_type.pizza_types.name
    slot_type_version = aws_lex_slot_type.pizza_types.version

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What kind of pizza do you want? You can choose cheese, pepperoni, or veggie!"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name           = "PizzaSize"
    slot_type      = aws_lex_slot_type.pizza_sizes.name
    slot_type_version = aws_lex_slot_type.pizza_sizes.version

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size pizza? Small, medium, or large?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Okay! You want a {PizzaSize} {PizzaType} pizza. Is that right?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "No problem! Let's start over. What kind of pizza would you like?"
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

