resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_iam_role" "lambda_role" {
  name = "pizza-bot-lambda-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_lambda_function" "pizza_order" {
  filename         = "lambda_function_payload.zip"
  function_name    = "pizza-order-handler-${random_id.suffix.hex}"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.handler"
  runtime          = "python3.11"
  source_code_hash = filebase64sha256("lambda_function_payload.zip")

  environment {
    variables = {
      PIZZA_SHOP_NAME = "Terraform Pizza"
    }
  }

  depends_on = [aws_iam_role_policy_attachment.lambda_basic]
}

resource "aws_lambda_permission" "lex_invoke" {
  statement_id  = "AllowLexInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_order.function_name
  principal     = "lex.amazonaws.com"
  source_arn    = "arn:aws:lex:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:bot:${aws_lex_bot.pizza_order.name}:*"
}

data "aws_region" "current" {}

data "aws_caller_identity" "current" {}

resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizzaIntent-${random_id.suffix.hex}"

  sample_utterances = [
    "I want to order a pizza",
    "I'd like a pizza",
    "Order a pizza",
    "I want pizza",
    "Can I get a pizza",
    "Pizza please"
  ]

  fulfillment_activity {
    type = "Lambda"
    lambda {
      lambda_function_arn = aws_lambda_function.pizza_order.arn
    }
  }

  slot {
    name           = "PizzaType"
    description    = "The type of pizza to order"
    slot_constraint = "Required"
    slot_type      = "PizzaTypeValues"
    slot_type_version = "$LATEST"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What type of pizza would you like? We have pepperoni, cheese, and veggie."
      }
    }
  }

  slot {
    name           = "PizzaSize"
    description    = "The size of the pizza"
    slot_constraint = "Required"
    slot_type      = "PizzaSizeValues"
    slot_type_version = "$LATEST"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What size would you like? Small, medium, or large?"
      }
    }
  }

  slot {
    name           = "DeliveryAddress"
    description    = "The delivery address"
    slot_constraint = "Required"
    slot_type      = "AMAZON.PostalAddress"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What address should we deliver to?"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content_type = "PlainText"
      content      = "I'll order a {PizzaSize} {PizzaType} pizza to {DeliveryAddress}. Is that correct?"
    }
  }

  rejection_statement {
    message {
      content_type = "PlainText"
      content      = "Okay, I've cancelled your order. Let me know if you'd like to order something else."
    }
  }
}

resource "aws_lex_slot_type" "pizza_type" {
  name = "PizzaTypeValues-${random_id.suffix.hex}"
  description = "Types of pizza available"

  enumeration_value {
    value = "pepperoni"
  }
  enumeration_value {
    value = "cheese"
  }
  enumeration_value {
    value = "veggie"
  }
  enumeration_value {
    value = "supreme"
  }

  value_selection_strategy = "ORIGINAL_VALUE"
}

resource "aws_lex_slot_type" "pizza_size" {
  name = "PizzaSizeValues-${random_id.suffix.hex}"
  description = "Sizes of pizza available"

  enumeration_value {
    value = "small"
    synonyms = ["S", "personal"]
  }
  enumeration_value {
    value = "medium"
    synonyms = ["M", "regular"]
  }
  enumeration_value {
    value = "large"
    synonyms = ["L", "family"]
  }

  value_selection_strategy = "ORIGINAL_VALUE"
}

resource "aws_lex_bot" "pizza_order" {
  name        = "PizzaOrderBot-${random_id.suffix.hex}"
  description = "Bot for ordering pizzas"
  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = aws_lex_intent.order_pizza.version
  }

  child_directed = false

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I couldn't understand. Please try again later."
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content_type = "PlainText"
      content      = "I didn't understand that. Can you please rephrase? You can say things like 'I want to order a pizza'."
    }
  }

  idle_session_ttl_in_seconds = 300
  locale                      = "en-US"
  process_behavior            = "SAVE"
  voice_id                    = "Salli"

  depends_on = [aws_lex_intent.order_pizza, aws_lex_slot_type.pizza_type, aws_lex_slot_type.pizza_size]
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_lambda_permission" "allow_lex_to_start_execution" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.hello_pizza.function_name
  principal     = "lex.amazonaws.com"
  # source_arn    = "${aws_lex_bot.order_pizza.arn}:$LATEST"
}

data "archive_file" "hello_pizza" {
  type        = "zip"
  source_file = "./supplement/hello_pizza.py"
  output_path = "./supplement/hello_pizza.zip"
}

resource "aws_lambda_function" "hello_pizza" {
  function_name = "hello_pizza"
  role          = aws_iam_role.iam_exec_role.arn
  filename      = data.archive_file.hello_pizza.output_path
  source_code_hash = data.archive_file.hello_pizza.output_base64sha256
  handler       = "hello_pizza.handler"
  runtime       = "python3.12"
}

resource "aws_iam_role" "iam_exec_role" {
  name = "iam-exec-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_lex_intent" "OrderPizza" {
  name = "OrderPizza"

  sample_utterances = [
    "I would like to pick up a pizza",
    "I would like to order some pizzas",
  ]

  slot {
    name                     = "PizzaType"
    description              = "Type of pizza to order"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.AlphaNumeric"
    priority                 = 1
    value_elicitation_prompt {
      message {
        content             = "What type of pizza would you like?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      uri            = aws_lambda_function.hello_pizza.arn
      message_version = "1.0"
    }
  }
}

resource "aws_lex_bot" "order_pizza" {
  name     = "OrderPizza"
  description  = "Orders a pizza from a local pizzeria"

  idle_session_ttl_in_seconds = 600
  locale = "en-US"

  child_directed = false

  voice_id = "Salli"
  process_behavior = "BUILD"

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't understand that, can you please repeat?"
      content_type = "PlainText"
    }
  }

  abort_statement {
    message {
      content      = "Sorry, I could not understand. Goodbye."
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.OrderPizza.name
    intent_version = aws_lex_intent.OrderPizza.version
  }

  # depends_on = [aws_lambda_permission.allow_lex_to_start_execution]
}

