  }
}

resource "aws_kendra_data_source" "example" {
  index_id = aws_kendra_index.example.id
  name     = "example-data-source"
  type     = "WEBCRAWLER"

  role_arn = aws_iam_role.data_source.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_urls = [
            "https://example.com"
          ]
          web_crawler_mode = "HOST_ONLY"
        }
      }

      url_exclusion_patterns = [
        ".*\/private\/.*",
        ".*\/admin\/.*",
        ".*\.pdf$",
        "https://example.com/internal/.*"
      ]

      url_inclusion_patterns = [
        "https://example.com/docs/.*",
        "https://example.com/blog/.*",
        ".*\/public\/.*"
      ]

      crawl_depth     = 3
      max_links_per_page = 100
      max_content_size_per_page_in_mega_bytes = 50
      max_urls_per_minute_crawl_rate = 300
    }
  }

  schedule = "cron(0 12 * * ? *)"

  tags = {
    Name = "Example Kendra Data Source"
  }
}

