provider "aws" {
  region = var.region
}

data "aws_caller_identity" "current" {}

data "aws_ecr_repository" "app" {
  name = var.ecr_repository_name
}

data "aws_ecr_image" "stable" {
  repository_name = data.aws_ecr_repository.app.name
  image_tag       = "stable"
}

locals {
  image_tag      = data.aws_ecr_image.stable.image_tag != "" ? data.aws_ecr_image.stable.image_tag : "latest"
  workspace_name = terraform.workspace

  tags = {
    Environment = local.workspace_name
    ManagedBy   = "Terraform"
    Project     = "EKS-Cluster"
  }
}

module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 20.0"

  cluster_name    = "eks-cluster-${local.workspace_name}"
  cluster_version = "1.29"

  cluster_endpoint_public_access  = true
  cluster_endpoint_private_access = true

  vpc_id     = aws_vpc.main.id
  subnet_ids = aws_subnet.private[*].id

  eks_managed_node_groups = {
    default = {
      desired_size = 2
      min_size     = 1
      max_size     = 4

      instance_types = ["m6i.large", "m5.large"]
      capacity_type  = "ON_DEMAND"

      labels = {
        environment = local.workspace_name
      }

      tags = local.tags
    }
  }

  enable_cluster_autoscaler = true

  cluster_addons = {
    coredns = {
      most_recent = true
    }
    kube-proxy = {
      most_recent = true
    }
    vpc-cni = {
      most_recent = true
    }
  }

  tags = local.tags
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = merge(local.tags, {
    Name = "eks-vpc-${local.workspace_name}"
  })
}

resource "aws_subnet" "private" {
  count             = 3
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = merge(local.tags, {
    Name                                        = "eks-private-subnet-${count.index + 1}"
    "kubernetes.io/role/internal-elb"           = "1"
    "kubernetes.io/cluster/eks-cluster-${local.workspace_name}" = "owned"
  })
}

