data "aws_eks_cluster_auth" "example" {
  name = aws_eks_cluster.example.name
}

resource "null_resource" "patch_coredns" {
  triggers = {
    always_run = timestamp()
  }

  provisioner "local-exec" {
    command = <<-EOT
      kubectl patch deployment coredns \n        -n kube-system \n        --type json \n        -p='[{"op": "remove", "path": "/spec/template/metadata/annotations/eks.amazonaws.com~1compute-type"}]' \n        --server=${aws_eks_cluster.example.endpoint} \n        --certificate-authority=/dev/stdin \n        --token=${data.aws_eks_cluster_auth.example.token} \n        <<< '${aws_eks_cluster.example.certificate_authority[0].data}' | base64 -d
    EOT
  }

  depends_on = [aws_eks_fargate_profile.kube_system]
}

