    Name = "shared-efs"
  }
}

resource "aws_efs_mount_target" "main" {
  count           = 2
  file_system_id  = aws_efs_file_system.shared.id
  subnet_id       = aws_subnet.private[count.index].id
  security_groups = [aws_security_group.efs.id]
}

resource "aws_iam_role" "ec2_efs_role" {
  name = "ec2-efs-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "amazon_ssm_managed_instance_core" {
  role       = aws_iam_role.ec2_efs_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

resource "aws_iam_instance_profile" "ec2_efs_profile" {
  name = "ec2-efs-profile"
  role = aws_iam_role.ec2_efs_role.name
}

resource "aws_instance" "private" {
  count                  = 2
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private[count.index].id
  vpc_security_group_ids = [aws_security_group.ec2.id]
  iam_instance_profile   = aws_iam_instance_profile.ec2_efs_profile.name

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils nfs-utils
              mkdir -p /mnt/efs
              mount -t efs -o tls ${aws_efs_file_system.shared.id}:/ /mnt/efs
              echo "${aws_efs_file_system.shared.id}:/ /mnt/efs efs _netdev,tls 0 0" >> /etc/fstab
              EOF

  tags = {
    Name = "private-ec2-${count.index + 1}"
  }

  depends_on = [aws_efs_mount_target.main]
}
