resource "aws_sagemaker_pipeline" "example" {
  pipeline_name         = "example-pipeline"
  pipeline_display_name = "Example Pipeline"
  role_arn              = aws_iam_role.example.arn

  pipeline_definition {
    pipeline_definition_body = jsonencode({
      Version = "2020-12-01"
      Metadata = {
        "com.amazonaws.sagemaker.pipeline.sdk.metadata" = {
          PythonSdkVersion = "2.0.0"
          CreatedBy = {
            UserProfileArn  = "arn:aws:sagemaker:us-east-1:123456789012:user-profile/d-abcdefghijklmnop/default"
            UserProfileName = "default"
            DomainId        = "d-abcdefghijklmnop"
          }
        }
      }
      Parameters = [
        {
          Name        = "InputDataUrl"
          Type        = "String"
          DefaultValue = "s3://my-bucket/input/data.csv"
        },
        {
          Name        = "ModelOutputPath"
          Type        = "String"
          DefaultValue = "s3://my-bucket/output"
        }
      ]
      Steps = [
        {
          Name = "PreprocessStep"
          Type = "Processing"
          Arguments = {
            ProcessingResources = {
              ClusterConfig = {
                InstanceCount  = 1
                InstanceType   = "ml.m5.xlarge"
                VolumeSizeInGB = 30
              }
            }
            AppSpecification = {
              ImageUri = "123456789012.dkr.ecr.us-east-1.amazonaws.com/preprocessing:latest"
            }
            ProcessingInputs = [
              {
                InputName = "input-1"
                S3Input = {
                  S3Uri        = { "Get" = "Parameters.InputDataUrl" }
                  S3DataType   = "S3Prefix"
                  S3InputMode  = "File"
                  S3DataDistributionType = "FullyReplicated"
                }
              }
            ]
            ProcessingOutputConfig = {
              Outputs = [
                {
                  OutputName = "output-1"
                  S3Output = {
                    S3Uri     = { "Get" = "Parameters.ModelOutputPath" }
                    S3UploadMode = "EndOfJob"
                  }
                }
              ]
            }
          }
        },
        {
          Name = "TrainingStep"
          Type = "Training"
          Arguments = {
            AlgorithmSpecification = {
              TrainingImage = "123456789012.dkr.ecr.us-east-1.amazonaws.com/training:latest"
              TrainingInputMode = "File"
            }
            OutputDataConfig = {
              S3OutputPath = { "Get" = "Parameters.ModelOutputPath" }
            }
            ResourceConfig = {
              InstanceCount  = 1
              InstanceType   = "ml.m5.xlarge"
              VolumeSizeInGB = 50
            }
            RoleArn = aws_iam_role.example.arn
            InputDataConfig = [
              {
                ChannelName = "training"
                DataSource = {
                  S3DataSource = {
                    S3DataType = "S3Prefix"
                    S3Uri      = { "Get" = "Parameters.InputDataUrl" }
                    S3DataDistributionType = "FullyReplicated"
                  }
                }
              }
            ]
            StoppingCondition = {
              MaxRuntimeInSeconds = 3600
            }
          }
        }
      ]
    })
  }

  tags = {
    Environment = "production"
    Project     = "ml-pipeline"
  }
}

resource "aws_iam_role" "example" {
  name = "sagemaker-pipeline-role"

  assume_role_policy = jsonencode({
