      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

data "aws_region" "current" {}

data "aws_caller_identity" "current" {}

resource "aws_mskconnect_connector" "debezium" {
  name = "debezium-connector"

  kafkaconnect_version = "2.7.1"

  capacity {
    autoscaling {
      mcu_count        = 1
      min_worker_count = 1
      max_worker_count = 2

      scale_in_policy {
        cpu_utilization_percentage = 20
      }

      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }

  connector_configuration = {
    "connector.class"                = "io.debezium.connector.mysql.MySqlConnector"
    "database.hostname"              = "example-mysql.example.com"
    "database.port"                  = "3306"
    "database.user"                  = "debezium"
    "database.password"              = "password"
    "database.server.id"             = "184054"
    "database.server.name"           = "dbserver1"
    "database.include.list"          = "inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.example.bootstrap_brokers_tls
    "database.history.kafka.topic"   = "schema-changes.inventory"
    "include.schema.changes"         = "true"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_tls

      vpc {
        security_groups = [aws_security_group.msk.id]
        subnets         = aws_subnet.msk[*].id
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "NONE"
  }

  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }

  plugin {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium.arn
      revision = aws_mskconnect_custom_plugin.debezium.latest_revision
    }
  }

  service_execution_role_arn = aws_iam_role.msk_connect.arn

  worker_configuration {
    arn      = aws_mskconnect_worker_configuration.example.arn
    revision = aws_mskconnect_worker_configuration.example.latest_revision
  }

  depends_on = [aws_msk_cluster.example]
}
```

