data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<-EOF
      import json
      import boto3
      import os

      def handler(event, context):
          codebuild = boto3.client('codebuild')

          # Extract student submission info from GitHub webhook
          body = json.loads(event.get('body', '{}'))
          repo_url = body.get('repository', {}).get('clone_url', '')
          commit_id = body.get('after', '')
          student_id = body.get('pusher', {}).get('name', 'unknown')

          response = codebuild.start_build(
              projectName=os.environ['CODEBUILD_PROJECT'],
              environmentVariablesOverride=[
                  {
                      'name': 'STUDENT_REPO_URL',
                      'value': repo_url
                  },
                  {
                      'name': 'COMMIT_ID',
                      'value': commit_id
                  },
                  {
                      'name': 'STUDENT_ID',
                      'value': student_id
                  }
              ]
          )

          return {
              'statusCode': 200,
              'body': json.dumps({
                  'buildId': response['build']['id'],
                  'message': 'Autograder started successfully'
              })
          }
    EOF
    filename = "index.py"
  }
}

