  name          = "autograder-project-${random_id.suffix.hex}"
  description   = "Autograder for CS class"
  build_timeout = "30"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.autograder_results.bucket
    packaging = "ZIP"
    name     = "autograder-results.zip"
  }

  environment {
