  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "autograder-codebuild-policy-${random_id.suffix.hex}"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_codebuild_source_credential" "github" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_token
}

resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project-${random_id.suffix.hex}"
  description   = "Autograder for CS class"
  build_timeout = "30"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.autograder_results.bucket
    packaging = "ZIP"
    name     = "autograder-results.zip"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false
  }

  source {
    type            = "GITHUB"
    location        = var.github_repository_url
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.9
        pre_build:
          commands:
            - echo "Installing autograder dependencies..."
            - pip install -r requirements.txt || true
        build:
          commands:
            - echo "Running autograder..."
            - python run_autograder.py || python autograder.py || echo "Running student code..."
            - mkdir -p results
            - echo "Test completed at $(date)" > results/test_output.txt
        post_build:
          commands:
            - echo "Uploading results to S3..."
            - cp results/test_output.txt $CODEBUILD_SRC_DIR/
      artifacts:
        files:
          - '**/*'
        base-directory: results
    EOT
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-log-group-${random_id.suffix.hex}"
      stream_name = "autograder-log-stream"
    }
  }

  tags = {
    Purpose = "CS Autograder"
  }
}

variable "github_token" {
  description = "GitHub personal access token for accessing the repository"
  type        = string
  sensitive   = true
}

variable "github_repository_url" {
  description = "URL of the GitHub repository containing student code"
  type        = string
}
```

