# VPC Configuration for isolated autograder environment
resource "aws_vpc" "autograder" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Private subnet with no internet access
resource "aws_subnet" "autograder_private" {
  vpc_id            = aws_vpc.autograder.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "autograder-private-subnet"
  }
}

# VPC Endpoint for CodeBuild to access AWS services without internet
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.autograder.id
  service_name = "com.amazonaws.${data.aws_region.current.name}.s3"
  route_table_ids = [aws_route_table.private.id]

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

resource "aws_vpc_endpoint" "codebuild" {
  vpc_id              = aws_vpc.autograder.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.codebuild"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.autograder_private.id]
  security_group_ids  = [aws_security_group.codebuild_endpoint.id]
  private_dns_enabled = true

  tags = {
    Name = "autograder-codebuild-endpoint"
  }
}

resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.autograder.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.autograder_private.id]
  security_group_ids  = [aws_security_group.codebuild_endpoint.id]
  private_dns_enabled = true

  tags = {
    Name = "autograder-logs-endpoint"
  }
}

# Route table for private subnet (no internet gateway)
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.autograder.id

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.autograder_private.id
  route_table_id = aws_route_table.private.id
}

# Security group for VPC endpoints
resource "aws_security_group" "codebuild_endpoint" {
  name        = "codebuild-endpoint-sg"
  description = "Security group for CodeBuild VPC endpoints"
  vpc_id      = aws_vpc.autograder.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = []
  }

  tags = {
    Name = "codebuild-endpoint-sg"
  }
}

# Security group for CodeBuild (no outbound internet)
resource "aws_security_group" "codebuild" {
  name        = "autograder-codebuild-sg"
  description = "Security group for autograder CodeBuild - no internet access"
  vpc_id      = aws_vpc.autograder.id

  # No ingress rules - CodeBuild doesn't need inbound connections

  # Egress only to VPC endpoints and S3
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder.cidr_block]
  }

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

