}

# CodeBuild project for autograder
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder"
  description   = "Autograder for CS class - runs student code in isolated environment"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.autograder_results.id
    path     = "build-output/"
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    # Environment variables for the autograder
    environment_variable {
      name  = "AUTOGRADER_MODE"
      value = "secure"
    }

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.id
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/cs-autograder-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"

    git_submodules_config {
      fetch_submodules = false
    }
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder.id
    subnets            = [aws_subnet.autograder_private.id]
    security_group_ids = [aws_security_group.codebuild.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-autograder"
      stream_name = "autograder-logs"
    }
  }

  tags = {
    Name = "cs-autograder"
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder" {
  name              = "/aws/codebuild/cs-autograder"
  retention_in_days = 7

  tags = {
    Name = "autograder-logs"
  }
}

# Optional: SNS topic for autograder notifications
resource "aws_sns_topic" "autograder_notifications" {
  name = "autograder-notifications"

  tags = {
    Name = "autograder-notifications"
  }
}

