  }
}

# Route table for private subnet (no internet gateway)
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.autograder.id

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.autograder_private.id
  route_table_id = aws_route_table.private.id
}

# Security group for VPC endpoints
resource "aws_security_group" "codebuild_endpoint" {
  name        = "codebuild-endpoint-sg"
  description = "Security group for CodeBuild VPC endpoints"
  vpc_id      = aws_vpc.autograder.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = []
  }

  tags = {
    Name = "codebuild-endpoint-sg"
  }
}

# Security group for CodeBuild (no outbound internet)
resource "aws_security_group" "codebuild" {
  name        = "autograder-codebuild-sg"
  description = "Security group for autograder CodeBuild - no internet access"
  vpc_id      = aws_vpc.autograder.id

  # No ingress rules - CodeBuild doesn't need inbound connections

  # Egress only to VPC endpoints and S3
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder.cidr_block]
  }

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

# S3 bucket for storing autograder results
