  vpc_config {
    vpc_id             = aws_vpc.autograder.id
    subnets            = [aws_subnet.autograder_private.id]
    security_group_ids = [aws_security_group.codebuild.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-autograder"
      stream_name = "autograder-logs"
    }
  }

  tags = {
    Name = "cs-autograder"
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder" {
  name              = "/aws/codebuild/cs-autograder"
  retention_in_days = 7

  tags = {
    Name = "autograder-logs"
  }
}

