# CodeBuild Project
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Autograder for CS class - runs student code in isolated environment"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild_service_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.results.id
    }

    environment_variable {
      name  = "SUBMISSIONS_BUCKET"
      value = aws_s3_bucket.submissions.id
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repo_url
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2

      phases:
        pre_build:
          commands:
            - echo "Starting autograder at $(date)"
            - aws s3 cp s3://$SUBMISSIONS_BUCKET/$CODEBUILD_BUILD_ID/submission.zip ./submission.zip || echo "No submission.zip found"
        build:
          commands:
            - echo "Running student code in isolated environment..."
            - |
              # Create isolated environment with network namespace
              unshare --net --pid --fork --mount-proc /bin/bash -c '
                # Disable all network interfaces in the namespace
                ip link set lo down 2>/dev/null || true

                # Run the student code
                if [ -f submission.zip ]; then
                  unzip -q submission.zip
                  chmod -R 755 .

                  # Run with timeout and resource limits
                  timeout 300 python3 -c "
                    import resource
                    import sys
                    # Limit memory to 512MB
                    resource.setrlimit(resource.RLIMIT_AS, (536870912, 536870912))
                    # Limit CPU time to 60 seconds
                    resource.setrlimit(resource.RLIMIT_CPU, (60, 60))

                    # Execute student code
                    exec(open("main.py").read())
                  " 2>&1 || echo "EXECUTION_FAILED: $?"
                else
                  echo "ERROR: No submission found"
                fi
              '
        post_build:
          commands:
            - echo "Autograder completed at $(date)"
            - |
              # Upload results to S3
              cat << 'RESULTS' > /tmp/result.json
              {
                "build_id": "$CODEBUILD_BUILD_ID",
                "timestamp": "$(date -u +%Y-%m-%dT%H:%M:%SZ)",
                "status": "COMPLETED"
              }
              RESULTS
            - aws s3 cp /tmp/result.json s3://$RESULTS_BUCKET/$CODEBUILD_BUILD_ID/result.json

      artifacts:
        files:
          - '**/*'
    EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder.id
    subnets            = [aws_subnet.autograder.id]
    security_group_ids = [aws_security_group.autograder.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograder"
      stream_name = "build-log"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.results.id}/build-logs"
    }
  }

  tags = {
    Name = "autograder-project"
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder" {
  name              = "/aws/codebuild/autograder"
  retention_in_days = 7

  tags = {
    Name = "autograder-logs"
  }
}

# Lambda function to trigger autograder on S3 upload
resource "aws_iam_role" "lambda_role" {
  name = "autograder-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  name = "autograder-lambda-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:StartBuild"
        ]
        Resource = aws_codebuild_project.autograder.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject"
        ]
        Resource = "${aws_s3_bucket.submissions.arn}/*"
      }
    ]
  })
}

resource "aws_lambda_function" "autograder_trigger" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "autograder-trigger"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  timeout          = 30
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  environment {
    variables = {
      CODEBUILD_PROJECT_NAME = aws_codebuild_project.autograder.name
    }
  }

  vpc_config {
    subnet_ids         = [aws_subnet.autograder.id]
    security_group_ids = [aws_security_group.autograder.id]
  }

  tags = {
    Name = "autograder-trigger"
  }
}

data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<-EOF
      import json
      import boto3
      import os
      import urllib.parse

      codebuild = boto3.client('codebuild')

      def handler(event, context):
          print("Received event:", json.dumps(event))

          bucket = event['Records'][0]['s3']['bucket']['name']
          key = urllib.parse.unquote_plus(event['Records'][0]['s3']['object']['key'])

          # Extract build ID from key path (expected: student-id/assignment-id/submission.zip)
          path_parts = key.split('/')
          build_id = '-'.join(path_parts[:-1]) if len(path_parts) > 1 else 'default'

          try:
              response = codebuild.start_build(
                  projectName=os.environ['CODEBUILD_PROJECT_NAME'],
                  sourceVersion='master',
                  environmentVariablesOverride=[
                      {
                          'name': 'SUBMISSION_KEY',
                          'value': key
                      },
                      {
                          'name': 'BUILD_ID',
                          'value': build_id
                      }
                  ]
              )
              print(f"Started build: {response['build']['id']}")
              return {
                  'statusCode': 200,
                  'body': json.dumps({'buildId': response['build']['id']})
              }
          except Exception as e:
              print(f"Error starting build: {str(e)}")
              raise
      EOF
    filename = "index.py"
  }
}

resource "aws_lambda_permission" "allow_s3" {
  statement_id  = "AllowS3Invoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.autograder_trigger.function_name
  principal     = "s3.amazonaws.com"
  source_arn    = aws_s3_bucket.submissions.arn
}

resource "aws_s3_bucket_notification" "submissions" {
  bucket = aws_s3_bucket.submissions.id

  lambda_function {
    lambda_function_arn = aws_lambda_function.autograder_trigger.arn
    events              = ["s3:ObjectCreated:*"]
    filter_suffix       = ".zip"
  }

  depends_on = [aws_lambda_permission.allow_s3]
}

# Variables
variable "github_repo_url" {
  description = "GitHub repository URL containing the autograder base code"
  type        = string
  default     = "https://github.com/example/autograder-base.git"
}

# Outputs
output "submissions_bucket" {
  description = "S3 bucket for student submissions"
  value       = aws_s3_bucket.submissions.id
}

output "results_bucket" {
  description = "S3 bucket for autograder results"
  value       = aws_s3_bucket.results.id
}

output "codebuild_project" {
  description = "CodeBuild project name"
  value       = aws_codebuild_project.autograder.name
}
