# VPC for isolated autograder environment
resource "aws_vpc" "autograder" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Private subnet with no internet access
resource "aws_subnet" "autograder_private" {
  vpc_id                  = aws_vpc.autograder.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = false

  tags = {
    Name = "autograder-private-subnet"
  }
}

# Security group with no outbound internet access
resource "aws_security_group" "autograder" {
  name        = "autograder-sg"
  description = "Security group for autograder with no internet access"
  vpc_id      = aws_vpc.autograder.id

  # No egress rules = no outbound internet access

  tags = {
    Name = "autograder-sg"
  }
}

# S3 bucket for storing autograder results
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

resource "aws_s3_bucket" "autograder_results" {
  bucket = "autograder-results-${random_id.bucket_suffix.hex}"

  tags = {
    Name = "autograder-results"
  }
}

resource "aws_s3_bucket_versioning" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# S3 bucket for build artifacts/cache
resource "aws_s3_bucket" "autograder_cache" {
  bucket = "autograder-cache-${random_id.bucket_suffix.hex}"

  tags = {
    Name = "autograder-cache"
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild" {
  name = "autograder-codebuild-policy"
  role = aws_iam_role.codebuild.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetObjectVersion"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*",
          aws_s3_bucket.autograder_cache.arn,
          "${aws_s3_bucket.autograder_cache.arn}/*"
        ]
      }
    ]
  })
}

# VPC Endpoint for S3 (allows S3 access without internet)
resource "aws_vpc_endpoint" "s3" {
  vpc_id            = aws_vpc.autograder.id
  service_name      = "com.amazonaws.${data.aws_region.current.name}.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids   = [aws_route_table.autograder.id]

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

# Route table for private subnet
