  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "autograder" {
  subnet_id      = aws_subnet.autograder_private.id
  route_table_id = aws_route_table.autograder.id
}

# CodeBuild project for running student code
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder"
  description   = "Autograder for CS class assignments"
  service_role  = aws_iam_role.codebuild.arn
  build_timeout = "60"

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.autograder_results.bucket
    path     = "build-output/"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/cs-autograder-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder.id
    subnets            = [aws_subnet.autograder_private.id]
    security_group_ids = [aws_security_group.autograder.id]
  }

  cache {
    type     = "S3"
    location = aws_s3_bucket.autograder_cache.bucket
  }

  tags = {
    Name = "cs-autograder"
  }
}

# Data sources
data "aws_availability_zones" "available" {
  state = "available"
}

data "aws_region" "current" {}
