locals {
  upload_lambda_code = <<EOF
import json
import boto3
import base64
import uuid

s3 = boto3.client('s3')
BUCKET_NAME = '${aws_s3_bucket.cat_pictures.bucket}'

def handler(event, context):
    try:
        if event['httpMethod'] == 'POST':
            # Handle file upload
            body = base64.b64decode(event['body']) if event.get('isBase64Encoded') else event['body'].encode()
            content_type = event['headers'].get('Content-Type', 'image/jpeg')
            extension = content_type.split('/')[-1] if '/' in content_type else 'jpg'
            key = f"uploads/{uuid.uuid4()}.{extension}"

            s3.put_object(
                Bucket=BUCKET_NAME,
                Key=key,
                Body=body,
                ContentType=content_type
            )

            return {
                'statusCode': 200,
                'headers': {
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                'body': json.dumps({'message': 'Upload successful', 'key': key})
            }

        elif event['httpMethod'] == 'GET':
            # List and return random image
            response = s3.list_objects_v2(Bucket=BUCKET_NAME, Prefix='uploads/')
            objects = response.get('Contents', [])

            if not objects:
                return {
                    'statusCode': 404,
                    'headers': {'Access-Control-Allow-Origin': '*'},
                    'body': json.dumps({'message': 'No cat pictures found'})
                }

            import random
            random_obj = random.choice(objects)
            url = f"https://{BUCKET_NAME}.s3.amazonaws.com/{random_obj['Key']}"

            return {
                'statusCode': 200,
                'headers': {
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                'body': json.dumps({'url': url, 'key': random_obj['Key']})
            }

    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'error': str(e)})
        }
EOF
}

data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "/tmp/cat_pictures_lambda_${random_id.suffix.hex}.zip"

  source {
    content  = local.upload_lambda_code
    filename = "index.py"
  }
}

resource "aws_lambda_function" "cat_pictures" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "cat-pictures-${random_id.suffix.hex}"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.handler"
  runtime          = "python3.11"
  timeout          = 30
  memory_size      = 256
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pictures.bucket
    }
  }

  depends_on = [aws_iam_role_policy.lambda_s3_policy]
}

resource "aws_lambda_permission" "api_gateway" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_pictures.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_pictures.execution_arn}/*/*"
}

resource "aws_api_gateway_rest_api" "cat_pictures" {
  name        = "cat-pictures-api-${random_id.suffix.hex}"
  description = "API for cat picture uploads and random retrieval"

  endpoint_configuration {
    types = ["REGIONAL"]
  }
}

resource "aws_api_gateway_resource" "cats" {
  rest_api_id = aws_api_gateway_rest_api.cat_pictures.id
  parent_id   = aws_api_gateway_rest_api.cat_pictures.root_resource_id
  path_part   = "cats"
}

resource "aws_api_gateway_method" "get_cats" {
  rest_api_id   = aws_api_gateway_rest_api.cat_pictures.id
  resource_id   = aws_api_gateway_resource.cats.id
  http_method   = "GET"
