locals {
  upload_lambda_code = <<EOF
import json
import boto3
import base64
import uuid

s3 = boto3.client('s3')
BUCKET_NAME = '${aws_s3_bucket.cat_pictures.bucket}'

def handler(event, context):
    try:
        if event['httpMethod'] == 'POST':
            # Handle file upload
            body = base64.b64decode(event['body']) if event.get('isBase64Encoded') else event['body'].encode()
            content_type = event['headers'].get('Content-Type', 'image/jpeg')
            extension = content_type.split('/')[-1] if '/' in content_type else 'jpg'
            key = f"uploads/{uuid.uuid4()}.{extension}"

            s3.put_object(
                Bucket=BUCKET_NAME,
                Key=key,
                Body=body,
                ContentType=content_type
            )

            return {
                'statusCode': 200,
                'headers': {
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                'body': json.dumps({'message': 'Upload successful', 'key': key})
            }

        elif event['httpMethod'] == 'GET':
            # List and return random image
            response = s3.list_objects_v2(Bucket=BUCKET_NAME, Prefix='uploads/')
            objects = response.get('Contents', [])

            if not objects:
                return {
                    'statusCode': 404,
                    'headers': {'Access-Control-Allow-Origin': '*'},
                    'body': json.dumps({'message': 'No cat pictures found'})
                }

            import random
            random_obj = random.choice(objects)
            url = f"https://{BUCKET_NAME}.s3.amazonaws.com/{random_obj['Key']}"

            return {
                'statusCode': 200,
                'headers': {
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                'body': json.dumps({'url': url, 'key': random_obj['Key']})
            }

    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'error': str(e)})
        }
EOF
}

