  source {
    content  = <<-EOF
      import json
      import boto3
      import base64
      import random
      import uuid
      import re

      s3 = boto3.client('s3')
      BUCKET = '${aws_s3_bucket.cat_pictures.bucket}'

      def lambda_handler(event, context):
          method = event['httpMethod']
          path = event['path']

          if method == 'POST' and path == '/upload':
              body = event.get('body', '')
              is_base64 = event.get('isBase64Encoded', False)

              if is_base64:
                  file_content = base64.b64decode(body)
              else:
                  file_content = body.encode('utf-8')

              key = f"cats/{uuid.uuid4()}.jpg"
              s3.put_object(Bucket=BUCKET, Key=key, Body=file_content, ContentType='image/jpeg')

              return {
                  'statusCode': 200,
                  'headers': {'Access-Control-Allow-Origin': '*'},
                  'body': json.dumps({'message': 'Cat picture uploaded!', 'key': key})
              }

          elif method == 'GET' and path == '/random':
              response = s3.list_objects_v2(Bucket=BUCKET, Prefix='cats/')
              objects = response.get('Contents', [])

              if not objects:
                  return {
                      'statusCode': 404,
                      'headers': {'Access-Control-Allow-Origin': '*'},
                      'body': json.dumps({'error': 'No cat pictures found'})
                  }

              random_obj = random.choice(objects)
              url = s3.generate_presigned_url(
                  'get_object',
                  Params={'Bucket': BUCKET, 'Key': random_obj['Key']},
                  ExpiresIn=300
              )

              return {
                  'statusCode': 302,
                  'headers': {
                      'Location': url,
                      'Access-Control-Allow-Origin': '*'
                  },
                  'body': ''
              }

          return {
              'statusCode': 400,
              'headers': {'Access-Control-Allow-Origin': '*'},
              'body': json.dumps({'error': 'Invalid request'})
          }
    EOF
    filename = "index.py"
  }
