data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<EOF
import json
import boto3
import uuid
import base64
import random
import os

s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')

BUCKET_NAME = os.environ['BUCKET_NAME']
TABLE_NAME = os.environ['TABLE_NAME']

def lambda_handler(event, context):
    table = dynamodb.Table(TABLE_NAME)

    if event['httpMethod'] == 'POST':
        # Upload cat picture
        body = json.loads(event['body'])
        image_data = base64.b64decode(body['image'])
        cat_id = str(uuid.uuid4())
        filename = f"{cat_id}.jpg"

        s3.put_object(
            Bucket=BUCKET_NAME,
            Key=filename,
            Body=image_data,
            ContentType='image/jpeg'
        )

        table.put_item(Item={
            'catId': cat_id,
            'filename': filename,
            'uploadedAt': str(context.aws_request_id)
        })

        return {
            'statusCode': 200,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'catId': cat_id, 'message': 'Cat picture uploaded successfully'})
        }

    elif event['httpMethod'] == 'GET':
        # Get random cat picture
        response = table.scan()
        items = response.get('Items', [])

        if not items:
            return {
                'statusCode': 404,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({'message': 'No cat pictures found'})
            }

        random_cat = random.choice(items)
        filename = random_cat['filename']

        url = s3.generate_presigned_url(
            'get_object',
            Params={'Bucket': BUCKET_NAME, 'Key': filename},
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'catId': random_cat['catId'], 'downloadUrl': url})
        }

    return {
        'statusCode': 400,
        'headers': {'Content-Type': 'application/json'},
        'body': json.dumps({'message': 'Unsupported method'})
    }
EOF
    filename = "lambda_function.py"
  }
}

resource "aws_lambda_function" "cat_api" {
  function_name = "cat-api-${random_id.suffix.hex}"
  role          = aws_iam_role.lambda_role.arn
  handler       = "lambda_function.lambda_handler"
  runtime       = "python3.11"
  filename      = data.archive_file.lambda_zip.output_path
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  timeout       = 30

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pictures.bucket
      TABLE_NAME  = aws_dynamodb_table.cat_metadata.name
    }
  }

  depends_on = [aws_iam_role_policy.lambda_policy]
}

