    Name        = "example-instance-${random_id.suffix.hex}"
    BackupDaily = "true"
  }

  root_block_device {
    volume_size = 20
    encrypted   = true
  }
}

data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

resource "aws_backup_vault" "example" {
  name = "example-vault-${random_id.suffix.hex}"
}

resource "aws_backup_plan" "example" {
  name = "example-daily-backup-plan-${random_id.suffix.hex}"

  rule {
    rule_name         = "daily-midnight-backup"
    target_vault_name = aws_backup_vault.example.name
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 30
    }

    copy_action {
      destination_vault_arn = aws_backup_vault.example.arn
    }
  }
}

resource "aws_backup_selection" "example" {
  iam_role_arn = aws_iam_role.backup.arn
  name         = "example-backup-selection-${random_id.suffix.hex}"
  plan_id      = aws_backup_plan.example.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "BackupDaily"
    value = "true"
  }
}

resource "aws_iam_role" "backup" {
  name = "example-aws-backup-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup.name
}

