    mysql -e "CREATE DATABASE myapp;"
    mysql -e "CREATE USER 'appuser'@'%' IDENTIFIED BY '${random_password.db.result}';"
    mysql -e "GRANT ALL PRIVILEGES ON myapp.* TO 'appuser'@'%';"
