  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_1_0"
}

resource "aws_lightsail_instance_public_ports" "example" {
  instance_name = aws_lightsail_instance.example.name

  port_info {
    protocol  = "tcp"
    from_port = 80
    to_port   = 80
  }
}

resource "aws_lightsail_distribution" "example" {
  name         = "example-distribution"
  bundle_id    = "small_1_0"
  is_enabled   = true

  origin {
    name        = aws_lightsail_instance.example.name
    region_name = aws_lightsail_instance.example.availability_zone
    protocol_policy = "http-only"
  }

  default_cache_behavior {
    behavior = "cache"
  }

  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD,OPTIONS,PUT,PATCH,POST,DELETE"
    cached_http_methods  = "GET,HEAD"

    default_ttl = 86400
    max_ttl     = 31536000
    min_ttl     = 0
  }
}
